population.algorithm:
Modified regret-based insertion with multi-route evaluation: For each ship order, compute insertion cost and second-best regret value across all existing non-empty routes and a potential new route, then insert into the route minimizing a composite score of direct cost and normalized regret penalty, always ensuring feasibility via trial insertion and reverting snapshots, falling back to seeding a new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type insertionInfo struct {
		idx      int
		cost     float64
		feasible bool
		regret   float64
	}

	for jj := range oris {
		shipID := total_ship + jj

		var candidates []insertionInfo
		bestFeasibleCost := 1e18
		secondBestFeasibleCost := 1e18

		// Evaluate all existing assigns (including possibly empty ones from earlier seeds)
		for i := 0; i < dispatch.AssignsLen; i++ {
			snapshotCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				isFeasible := newCost >= 0
				insertionCost := newCost - snapshotCost
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].Cost = snapshotCost
				dispatch.Assigns[i].GenRoute()

				if isFeasible {
					info := insertionInfo{idx: i, cost: insertionCost, feasible: true, regret: 0}
					candidates = append(candidates, info)

					if insertionCost < bestFeasibleCost {
						secondBestFeasibleCost = bestFeasibleCost
						bestFeasibleCost = insertionCost
					} else if insertionCost < secondBestFeasibleCost {
						secondBestFeasibleCost = insertionCost
					}
				}
			}
		}

		// Regret computation: difference between best and second-best in same route category (existing vs new)
		for k := range candidates {
			if candidates[k].cost <= bestFeasibleCost+1e-9 && secondBestFeasibleCost < 1e17 {
				candidates[k].regret = secondBestFeasibleCost - bestFeasibleCost
			} else {
				candidates[k].regret = 0
			}
		}

		// Evaluate a potential new empty assign if capacity allows
		newRouteIndex := dispatch.AssignsLen
		if dispatch.AssignsLen < MAXASSIGNS {
			snapshotCostNew := float64(0)
			if dispatch.AssignsLen < MAXASSIGNS {
				// Ensure the assign at newRouteIndex is initially clear (assumed zeroed)
				snapshotCostNew = dispatch.Assigns[newRouteIndex].Cost
			}
			ok := dispatch.Assigns[newRouteIndex].AddShip(shipID, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[newRouteIndex].GenRoute()
				newCostNew := dispatch.Assigns[newRouteIndex].Cost
				isFeasibleNew := newCostNew >= 0
				insertionCostNew := newCostNew - snapshotCostNew
				dispatch.Assigns[newRouteIndex].RemoveShip(shipID)
				dispatch.Assigns[newRouteIndex].Cost = snapshotCostNew
				dispatch.Assigns[newRouteIndex].GenRoute()

				if isFeasibleNew {
					// For a new route, regret relative to itself is zero, but we compare against best existing
					regretVal := 0.0
					if bestFeasibleCost < 1e17 {
						regretVal = insertionCostNew - bestFeasibleCost
						if regretVal < 0 {
							regretVal = 0
						}
					}
					info := insertionInfo{idx: newRouteIndex, cost: insertionCostNew, feasible: true, regret: regretVal}
					candidates = append(candidates, info)
				}
			}
		}

		selectedIdx := -1
		minScore := 1e18
		for _, c := range candidates {
			if !c.feasible {
				continue
			}
			score := c.cost + 0.3*c.regret
			if score < minScore {
				minScore = score
				selectedIdx = c.idx
			}
		}

		if selectedIdx >= 0 {
			if selectedIdx >= dispatch.AssignsLen {
				dispatch.Assigns[selectedIdx].AddShip(shipID, oris[jj], dess[jj])
				dispatch.Assigns[selectedIdx].GenRoute()
				dispatch.AssignsLen++
			} else {
				dispatch.Assigns[selectedIdx].AddShip(shipID, oris[jj], dess[jj])
				dispatch.Assigns[selectedIdx].GenRoute()
			}
		} else {
			// Fallback seed insertion
			if dispatch.AssignsLen < MAXASSIGNS {
				i := dispatch.AssignsLen
				dispatch.Assigns[i].AddShip(shipID, oris[jj], dess[jj])
				dispatch.Assigns[i].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

