		success := assign.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
		if success {
			assign.GenRoute()
			newCost := assign.Cost
			costDelta := newCost - oldCost
			waitTimePenalty := 0.0
			stations := assign.Stations[:assign.StationsLen]
			for k := 0; k < len(stations)-1; k++ {
				arrivalTime := stations[k].TimeStart
				nextStart := stations[k+1].TimeStart
				if arrivalTime > nextStart {
					waitTimePenalty += float64(arrivalTime-nextStart) * penaltyWeight
				}
			}
			travelDist := 0.0
			for k := 0; k < len(stations)-1; k++ {
				travelDist += cal_dis(stations[k], stations[k+1])
