func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	scoreThreshold := 10000.0
	penaltyWeight := 1.5
	insertionLimit := 3
	validIndices := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen >= 0 {
			validIndices = append(validIndices, i)
		}
	}
	for orderIdx := range oris {
		type candidate struct {
			idx        int
			score      float64
			costDelta  float64
			addSuccess bool
		}
		var candidates []candidate
		for _, assignIdx := range validIndices {
			assign := &dispatch.Assigns[assignIdx]
			oldCost := assign.Cost
			success := assign.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if success {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - oldCost
				waitTimePenalty := 0.0
				stations := assign.Stations[:assign.StationsLen]
				for k := 0; k < len(stations)-1; k++ {
					arrivalTime := stations[k].TimeStart
					nextStart := stations[k+1].TimeStart
					if arrivalTime > nextStart {
						waitTimePenalty += float64(arrivalTime-nextStart) * penaltyWeight
					}
				}
				travelDist := 0.0
				for k := 0; k < len(stations)-1; k++ {
					travelDist += cal_dis(stations[k], stations[k+1])
				}
				if travelDist == 0 {
					travelDist = 1
				}
				score := costDelta*penaltyWeight + waitTimePenalty/travelDist*100.0
				candidates = append(candidates, candidate{idx: assignIdx, score: score, costDelta: costDelta, addSuccess: true})
				assign.RemoveShip(total_ship + orderIdx)
				assign.GenRoute()
			} else {
				candidates = append(candidates, candidate{idx: assignIdx, score: math.Inf(1), costDelta: math.Inf(1), addSuccess: false})
			}
		}
		bestCandidateIdx := -1
		bestScore := math.Inf(1)
		sortCount := 0
		for ci := range candidates {
			if !candidates[ci].addSuccess {
				continue
			}
			if candidates[ci].score < bestScore && candidates[ci].costDelta <= scoreThreshold {
				bestScore = candidates[ci].score
				bestCandidateIdx = candidates[ci].idx
			}
			sortCount++
			if sortCount >= insertionLimit {
				break
			}
		}
		if bestCandidateIdx != -1 {
