func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	nOrders := len(oris)
	if nOrders != len(dess) || nOrders == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	var baseCosts [MAXASSIGNS]float64
	for i := 0; i < dispatch.AssignsLen; i++ {
		baseCosts[i] = dispatch.Assigns[i].Cost
	}
	nextNewRoute := dispatch.AssignsLen
	for orderIdx := 0; orderIdx < nOrders; orderIdx++ {
		shipID := total_ship + orderIdx
		bestCostInc := INF_COST
		bestAssignIdx := -1
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			ok := assign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}
			costInc := newCost - baseCosts[i]
			if costInc < bestCostInc {
				bestCostInc = costInc
				bestAssignIdx = i
			}
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}
		inserted := false
		if bestAssignIdx >= 0 && bestCostInc < INF_COST {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			baseCosts[bestAssignIdx] = dispatch.Assigns[bestAssignIdx].Cost
			inserted = true
		}
