population.algorithm:
Greedy insertion with regret-based candidate evaluation and fallback to earliest-available empty assign if all non-empty assigns fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	activeIndices := make([]int, 0, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			activeIndices = append(activeIndices, i)
		}
	}

	emptyStartIdx := dispatch.AssignsLen
	availableEmptySlots := MAXASSIGNS - dispatch.AssignsLen

	for jj := 0; jj < orderCount; jj++ {
		shipID := total_ship + jj
		bestAssignIdx := -1
		bestCostIncrease := math.MaxFloat64

		candidateCosts := make([]float64, 0, len(activeIndices)+availableEmptySlots)

		for _, idx := range activeIndices {
			oldCost := dispatch.Assigns[idx].Cost
			success := dispatch.Assigns[idx].AddShip(shipID, oris[jj], dess[jj])
			if success {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					increase := newCost - oldCost
					candidateCosts = append(candidateCosts, increase)
					if increase < bestCostIncrease {
						bestCostIncrease = increase
						bestAssignIdx = idx
					}
				}
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
			} else {
				candidateCosts = append(candidateCosts, math.Inf(1))
			}
		}

		if bestAssignIdx >= 0 {
			regretValue := 0.0
			if len(candidateCosts) >= 2 {
				sortedCosts := make([]float64, len(candidateCosts))
				copy(sortedCosts, candidateCosts)
				sort.Float64s(sortedCosts)
				validFound := 0
				firstValid := math.MaxFloat64
				secondValid := math.MaxFloat64
				for _, c := range sortedCosts {
					if c >= 0 && c < math.MaxFloat64/2 {
						if validFound == 0 {
							firstValid = c
							validFound++
						} else if validFound == 1 {
							secondValid = c
							validFound++
							break
						}
					}
				}
				if validFound >= 2 {
					regretValue = secondValid - firstValid
				}
			}

			finalChosenIdx := bestAssignIdx
			if len(candidateCosts) >= 2 && availableEmptySlots > 0 {
				minRegretThreshold := 50.0
				currentBest := candidateCosts[0]
				for ci, idx := range activeIndices {
					if candidateCosts[ci] >= 0 && candidateCosts[ci] < math.MaxFloat64/2 {
						if candidateCosts[ci] < currentBest {
							currentBest = candidateCosts[ci]
							bestAssignIdx = idx
						}
					}
				}
				anyHighRegret := false
				for ci := range candidateCosts {
					if candidateCosts[ci] >= 0 && candidateCosts[ci] < math.MaxFloat64/2 {
						if regretValue > minRegretThreshold {
							anyHighRegret = true
							break
						}
					}
				}
				if anyHighRegret && regretValue > minRegretThreshold {
					finalChosenIdx = bestAssignIdx
				}
			}

			dispatch.Assigns[finalChosenIdx].AddShip(shipID, oris[jj], dess[jj])
			dispatch.Assigns[finalChosenIdx].GenRoute()
		} else {
			fallbackAssigned := false
			for attempt := 0; attempt < 2; attempt++ {
				searchStart := 0
				if attempt == 1 {
					searchStart = emptyStartIdx
				}
				endLimit := dispatch.AssignsLen
				if attempt == 1 {
					endLimit = searchStart + 1
					if endLimit > MAXASSIGNS {
						endLimit = MAXASSIGNS
					}
				}

				for idx := searchStart; idx < endLimit; idx++ {
					if dispatch.Assigns[idx].StationsLen == 0 {
						if dispatch.Assigns[idx].AddShip(shipID, oris[jj], dess[jj]) {
							dispatch.Assigns[idx].GenRoute()
							if idx >= dispatch.AssignsLen {
								dispatch.AssignsLen = idx + 1
							}
							fallbackAssigned = true
							activeIndices = append(activeIndices, idx)
							break
						} else {
							dispatch.Assigns[idx].RemoveShip(shipID)
						}
					} else {
						if dispatch.Assigns[idx].AddShip(shipID, oris[jj], dess[jj]) {
							dispatch.Assigns[idx].GenRoute()
							if dispatch.Assigns[idx].Cost >= 0 {
								fallbackAssigned = true
								break
							} else {
								dispatch.Assigns[idx].RemoveShip(shipID)
								dispatch.Assigns[idx].GenRoute()
							}
						}
					}
				}
				if fallbackAssigned {
					break
				}

				if attempt == 0 && availableEmptySlots > 0 {
					newIdx := emptyStartIdx
					if dispatch.Assigns[newIdx].AddShip(shipID, oris[jj], dess[jj]) {
						dispatch.Assigns[newIdx].GenRoute()
						if dispatch.Assigns[newIdx].Cost >= 0 {
							dispatch.AssignsLen = newIdx + 1
							emptyStartIdx = newIdx + 1
							availableEmptySlots--
							activeIndices = append(activeIndices, newIdx)
							fallbackAssigned = true
						} else {
							dispatch.Assigns[newIdx].RemoveShip(shipID)
						}
					}
				}
				if fallbackAssigned {
					break
				}
			}

			if !fallbackAssigned && availableEmptySlots > 0 {
				newIdx := emptyStartIdx
				if newIdx < MAXASSIGNS {
					if dispatch.Assigns[newIdx].AddShip(shipID, oris[jj], dess[jj]) {
						dispatch.Assigns[newIdx].GenRoute()
						if dispatch.Assigns[newIdx].Cost >= 0 {
							dispatch.AssignsLen = newIdx + 1
							emptyStartIdx = newIdx + 1
							availableEmptySlots--
							activeIndices = append(activeIndices, newIdx)
						} else {
							dispatch.Assigns[newIdx].RemoveShip(shipID)
						}
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

