				sort.Float64s(sortedCosts)
				validFound := 0
				firstValid := math.MaxFloat64
				secondValid := math.MaxFloat64
				for _, c := range sortedCosts {
					if c >= 0 && c < math.MaxFloat64/2 {
						if validFound == 0 {
							firstValid = c
							validFound++
						} else if validFound == 1 {
							secondValid = c
							validFound++
							break
						}
					}
				}
				if validFound >= 2 {
					regretValue = secondValid - firstValid
				}
			}

			finalChosenIdx := bestAssignIdx
			if len(candidateCosts) >= 2 && availableEmptySlots > 0 {
				minRegretThreshold := 50.0
				currentBest := candidateCosts[0]
				for ci, idx := range activeIndices {
					if candidateCosts[ci] >= 0 && candidateCosts[ci] < math.MaxFloat64/2 {
						if candidateCosts[ci] < currentBest {
							currentBest = candidateCosts[ci]
							bestAssignIdx = idx
						}
					}
				}
				anyHighRegret := false
				for ci := range candidateCosts {
					if candidateCosts[ci] >= 0 && candidateCosts[ci] < math.MaxFloat64/2 {
						if regretValue > minRegretThreshold {
							anyHighRegret = true
							break
						}
					}
				}
				if anyHighRegret && regretValue > minRegretThreshold {
					finalChosenIdx = bestAssignIdx
