			fallbackAssigned := false
			for attempt := 0; attempt < 2; attempt++ {
				searchStart := 0
				if attempt == 1 {
					searchStart = emptyStartIdx
				}
				endLimit := dispatch.AssignsLen
				if attempt == 1 {
					endLimit = searchStart + 1
					if endLimit > MAXASSIGNS {
						endLimit = MAXASSIGNS
					}
				}

				for idx := searchStart; idx < endLimit; idx++ {
					if dispatch.Assigns[idx].StationsLen == 0 {
						if dispatch.Assigns[idx].AddShip(shipID, oris[jj], dess[jj]) {
							dispatch.Assigns[idx].GenRoute()
							if idx >= dispatch.AssignsLen {
								dispatch.AssignsLen = idx + 1
							}
							fallbackAssigned = true
							activeIndices = append(activeIndices, idx)
							break
						} else {
							dispatch.Assigns[idx].RemoveShip(shipID)
						}
					} else {
						if dispatch.Assigns[idx].AddShip(shipID, oris[jj], dess[jj]) {
							dispatch.Assigns[idx].GenRoute()
							if dispatch.Assigns[idx].Cost >= 0 {
								fallbackAssigned = true
								break
							} else {
								dispatch.Assigns[idx].RemoveShip(shipID)
								dispatch.Assigns[idx].GenRoute()
							}
						}
					}
				}
				if fallbackAssigned {
					break
				}

				if attempt == 0 && availableEmptySlots > 0 {
					newIdx := emptyStartIdx
					if dispatch.Assigns[newIdx].AddShip(shipID, oris[jj], dess[jj]) {
						dispatch.Assigns[newIdx].GenRoute()
						if dispatch.Assigns[newIdx].Cost >= 0 {
							dispatch.AssignsLen = newIdx + 1
							emptyStartIdx = newIdx + 1
							availableEmptySlots--
							activeIndices = append(activeIndices, newIdx)
							fallbackAssigned = true
						} else {
							dispatch.Assigns[newIdx].RemoveShip(shipID)
						}
					}
				}
				if fallbackAssigned {
					break
				}
			}

			if !fallbackAssigned && availableEmptySlots > 0 {
				newIdx := emptyStartIdx
				if newIdx < MAXASSIGNS {
					if dispatch.Assigns[newIdx].AddShip(shipID, oris[jj], dess[jj]) {
						dispatch.Assigns[newIdx].GenRoute()
						if dispatch.Assigns[newIdx].Cost >= 0 {
							dispatch.AssignsLen = newIdx + 1
							emptyStartIdx = newIdx + 1
							availableEmptySlots--
							activeIndices = append(activeIndices, newIdx)
						} else {
							dispatch.Assigns[newIdx].RemoveShip(shipID)
						}
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

