population.algorithm:
Greedily insert each ship by evaluating all positions in all assigns with a weighted scoring function combining distance savings, time window compatibility, and route compactness, preferring higher density routes first, then trying empty slots from lowest index, with a deterministic fallback to force-insert into any assign regardless of cost if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		wDistSavings = 1.0
		wTimeCompat  = 0.5
		wCompact     = 0.3
		penaltyLarge = 1e9
	)
	nonEmptyIndices := make([]int, 0, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			nonEmptyIndices = append(nonEmptyIndices, i)
		}
	}
	for orderIdx := range oris {
		shipID := total_ship + orderIdx
		bestScore := -math.MaxFloat64
		bestAssignIdx := -1
		var savedCosts map[int]float64
		if len(nonEmptyIndices) > 0 {
			savedCosts = make(map[int]float64, len(nonEmptyIndices))
			for _, idx := range nonEmptyIndices {
				savedCosts[idx] = dispatch.Assigns[idx].Cost
				if dispatch.Assigns[idx].AddShip(shipID, oris[orderIdx], dess[orderIdx]) {
					dispatch.Assigns[idx].GenRoute()
					if dispatch.Assigns[idx].Cost >= 0 {
						costInc := dispatch.Assigns[idx].Cost - savedCosts[idx]
						score := wDistSavings*(-costInc)
						ori, des := oris[orderIdx], dess[orderIdx]
						timeScore := 0.0
						if ori.TimeStart <= ori.TimeEnd && des.TimeStart <= des.TimeEnd {
							timeScore = 1.0
						}
						score += wTimeCompat * timeScore
						stationCnt := float64(dispatch.Assigns[idx].StationsLen)
						compactScore := 1.0 / (stationCnt + 1.0)
						score += wCompact * compactScore
						if score > bestScore {
							bestScore = score
							bestAssignIdx = idx
						}
					}
					dispatch.Assigns[idx].RemoveShip(shipID)
					dispatch.Assigns[idx].Cost = savedCosts[idx]
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
		placed := false
		if bestAssignIdx != -1 {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			placed = true
		} else {
			for tryIdx := 0; tryIdx < MAXASSIGNS; tryIdx++ {
				if dispatch.Assigns[tryIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx]) {
					dispatch.Assigns[tryIdx].GenRoute()
					if dispatch.Assigns[tryIdx].Cost >= 0 {
						if tryIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = tryIdx + 1
						}
						placed = true
						break
					} else {
						dispatch.Assigns[tryIdx].RemoveShip(shipID)
						dispatch.Assigns[tryIdx].GenRoute()
					}
				}
			}
		}
		if !placed {
			fallbackIdx := -1
			for tryIdx := 0; tryIdx < MAXASSIGNS; tryIdx++ {
				if dispatch.Assigns[tryIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx]) {
					fallbackIdx = tryIdx
					break
				}
			}
			if fallbackIdx != -1 {
				dispatch.Assigns[fallbackIdx].GenRoute()
				if fallbackIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = fallbackIdx + 1
				}
				placed = true
			}
		}
		if placed {
			nonEmptyIndices = nonEmptyIndices[:0]
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].StationsLen > 0 {
					nonEmptyIndices = append(nonEmptyIndices, i)
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

