		bestCandidate := candidate{-1, 0, 0, false}
		shipID := total_ship + jj
		for ii := 0; ii < dispatch.AssignsLen || ii == dispatch.AssignsLen; ii++ {
			var originalCost float64
			wasEmpty := false
			if ii < dispatch.AssignsLen {
				if dispatch.Assigns[ii].StationsLen == 0 {
					wasEmpty = true
