func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const REGRET_K = 3
    type candidate struct {
        idx   int
        score float64
        added bool
    }

    // Prepare non‑empty assigns indices for initial shuffling
    var nonEmptyIdx []int
    for i := 0; i < dispatch.AssignsLen; i++ {
        if dispatch.Assigns[i].StationsLen > 0 {
            nonEmptyIdx = append(nonEmptyIdx, i)
        }
    }
    // Shuffle non‑empty assigns once to avoid deterministic bias
    rand.Shuffle(len(nonEmptyIdx), func(i, j int) {
        nonEmptyIdx[i], nonEmptyIdx[j] = nonEmptyIdx[j], nonEmptyIdx[i]
    })

    // Precompute distances between stations for quick access
    distCache := make(map[[4]int]float64)

    getDist := func(a, b Station) float64 {
        key := [4]int{a.X, a.Y, b.X, b.Y}
        if v, ok := distCache[key]; ok {
            return v
        }
        d := cal_dis(a, b)
        distCache[key] = d
        return d
    }

    // Process each ship order sequentially
    for orderID := 0; orderID < len(oris); orderID++ {
        ori := oris[orderID]
        des := dess[orderID]
        shipID := total_ship + orderID

        // Evaluate insertion into every existing assign (including empty slots up to MAXASSIGNS)
        candidates := make([]candidate, 0, dispatch.AssignsLen+len(nonEmptyIdx)+10)
        // First consider already‑existing assigns (both non‑empty and possibly empty ones within current length)
        for ai := 0; ai < dispatch.AssignsLen; ai++ {
            cpy := dispatch.Assigns[ai]
            success := cpy.AddShip(shipID, ori, des)
            if success {
                cpy.GenRoute()
                if cpy.Cost >= 0 {
                    delta := cpy.Cost - dispatch.Assigns[ai].Cost
                    // Normalize delta by current assign cost to favor balanced loads
                    normDelta := delta
                    if dispatch.Assigns[ai].Cost > 0 {
                        normDelta = delta / (dispatch.Assigns[ai].Cost + 1e-6)
                    }
                    // Additional penalty for tight time windows violation risk
                    twPenalty := 0.0
                    if ori.TimeStart > 0 || ori.TimeEnd > 0 || des.TimeStart > 0 || des.TimeEnd > 0 {
                        // Simple heuristic: larger gap reduces penalty
                        gapOri := float64(ori.TimeEnd - ori.TimeStart)
                        gapDes := float64(des.TimeEnd - des.TimeStart)
                        if gapOri <= 0 || gapDes <= 0 {
                            twPenalty = 10000.0
                        } else {
                            twPenalty = 1.0 / (gapOri + gapDes + 1.0)
                        }
                    }
                    score := delta + 0.5*normDelta + 50.0*twPenalty
                    candidates = append(candidates, candidate{idx: ai, score: score, added: true})
                }
                cpy.RemoveShip(shipID)
                cpy.GenRoute()
            }
        }

        // Also try inserting into completely new/empty assign slots beyond current length (if capacity allows)
        // We limit search to at most MAXASSIGNS total assigns
