func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		type candidate struct {
			idx     int
			incCost float64
			regret  float64
			isNew   bool
		}
		var candidates []candidate

		baseDist := cal_dis(ori, des)
		if baseDist < 1e-9 {
			baseDist = 1.0
		}

		alpha := 1.0
		beta := 0.5

		timeWindowPressure := 0.0
		if ori.TimeEnd > ori.TimeStart {
			timeWindowPressure = 1.0 / float64(ori.TimeEnd-ori.TimeStart+1)
		}
		if des.TimeEnd > des.TimeStart {
			timeWindowPressure += 1.0 / float64(des.TimeEnd-des.TimeStart+1)
		}

		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			assignCopy := dispatch.Assigns[ii]
			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				delta := newCost - oldCost

				regretVal := 0.0
				loadRatio := 0.0
				if assignCopy.StationCurrent.Load > 0 {
					loadRatio = float64(assignCopy.StationCurrent.Load) / 100.0
				}

				timeSlack := 1.0
				if ori.TimeEnd > 0 && ori.TimeStart <= ori.TimeEnd {
					slack := float64(ori.TimeEnd - ori.TimeStart)
					if slack < 60 {
						timeSlack = slack / 60.0
					}
				}

				if delta > 0 {
					regretVal = delta * (1.0 + loadRatio + timeWindowPressure*(1.0/timeSlack))
				} else {
					regretVal = delta * (1.0 - loadRatio*0.3)
				}

				score := delta + alpha*regretVal*timeWindowPressure
				candidates = append(candidates, candidate{idx: ii, incCost: delta, regret: score, isNew: false})
			}
		}

		if dispatch.AssignsLen < MAXASSIGNS {
			emptyIdx := dispatch.AssignsLen
			assignCopy := dispatch.Assigns[emptyIdx]
			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				if newCost >= 0 {
					regretVal := newCost * (1.0 + timeWindowPressure*beta)
					candidates = append(candidates, candidate{idx: emptyIdx, incCost: newCost, regret: regretVal, isNew: true})
				}
			}
