			for _, cand := range candidates[1:] {
				if cand.regret < minRegret-eps {
					minRegret = cand.regret
					bestIdx = cand.idx
					bestInc = cand.incCost
				} else if math.Abs(cand.regret-minRegret) < eps && cand.incCost < bestInc-eps {
					bestIdx = cand.idx
					bestInc = cand.incCost
				}
			}

			ok := dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[bestIdx].GenRoute()
				if bestIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
				inserted = true
			}
		}

		if !inserted {
			fallbackCandidates := make([]int, 0, MAXASSIGNS)
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				fallbackCandidates = append(fallbackCandidates, ii)
			}

			if len(fallbackCandidates) > 1 {
