Adaptive batch insertion with regret-based assignment selection and capacity-aware probing, using multi-pass evaluation across feasible slots while maintaining route validity through incremental updates.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    orderIndices := make([]int, len(oris))
    for i := range orderIndices {
        orderIndices[i] = i
    }
    rand.Shuffle(len(orderIndices), func(i, j int) {
        orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
    })
    usedSlots := make([]bool, MAXASSIGNS)
    for i := 0; i < dispatch.AssignsLen; i++ {
        usedSlots[i] = true
    }
    for _, idx := range orderIndices {
        shippedID := total_ship + idx
        ori := oris[idx]
        des := dess[idx]
        bestSlot := -1
        bestRegret := -math.MaxFloat64
        bestDelta := math.MaxFloat64
        var secondBestDelta float64
        feasibleSlots := 0
        for si := 0; si < MAXASSIGNS; si++ {
            if !usedSlots[si] && si >= dispatch.AssignsLen {
                continue
            }
            costBefore := dispatch.Assigns[si].Cost
            ok := dispatch.Assigns[si].AddShip(shippedID, ori, des)
            if ok {
                dispatch.Assigns[si].GenRoute()
                if dispatch.Assigns[si].Cost >= 0 {
                    delta := dispatch.Assigns[si].Cost - costBefore
                    feasibleSlots++
                    if delta < bestDelta {
                        secondBestDelta = bestDelta
                        bestDelta = delta
                        bestSlot = si
                    } else if delta < secondBestDelta {
                        secondBestDelta = delta
                    }
                }
                dispatch.Assigns[si].RemoveShip(shippedID)
                dispatch.Assigns[si].GenRoute()
            }
        }
        if bestSlot != -1 && feasibleSlots > 0 {
            if secondBestDelta == math.MaxFloat64 {
                secondBestDelta = bestDelta * 2
            }
            regret := secondBestDelta - bestDelta
            if regret > bestRegret || feasibleSlots == 1 {
                bestRegret = regret
            }
            dispatch.Assigns[bestSlot].AddShip(shippedID, ori, des)
            dispatch.Assigns[bestSlot].GenRoute()
            usedSlots[bestSlot] = true
        } else {
            placed := false
            for si := 0; si < MAXASSIGNS; si++ {
                if !usedSlots[si] {
                    dispatch.Assigns[si].AddShip(shippedID, ori, des)
                    dispatch.Assigns[si].GenRoute()
                    if dispatch.Assigns[si].Cost >= 0 {
                        usedSlots[si] = true
                        if si >= dispatch.AssignsLen {
                            dispatch.AssignsLen = si + 1
                        }
                        placed = true
                        break
                    } else {
                        dispatch.Assigns[si].RemoveShip(shippedID)
                        dispatch.Assigns[si].GenRoute()
                    }
                }
            }
            if !placed {
                for si := 0; si < dispatch.AssignsLen; si++ {
                    if dispatch.Assigns[si].AddShip(shippedID, ori, des) {
                        dispatch.Assigns[si].GenRoute()
                        if dispatch.Assigns[si].Cost >= 0 {
                            placed = true
                            break
                        } else {
                            dispatch.Assigns[si].RemoveShip(shippedID)
                            dispatch.Assigns[si].GenRoute()
                        }
                    }
