                if !placed && dispatch.AssignsLen < MAXASSIGNS {
                    dispatch.Assigns[dispatch.AssignsLen].AddShip(shippedID, ori, des)
                    dispatch.Assigns[dispatch.AssignsLen].GenRoute()
                    if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
