for jj := range oris {
	ori := oris[jj]
	des := dess[jj]
	shipID := total_ship + jj

	type candidate struct {
		idx        int
		score      float64
		isNew      bool
		deltaCost  float64
		travelOnly float64
	}
	var candidates []candidate

	baseTravel := cal_dis(ori, des)

	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		oldCost := dispatch.Assigns[ii].Cost
		assignCopy := dispatch.Assigns[ii]
		ok := assignCopy.AddShip(shipID, ori, des)
		if ok {
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			delta := newCost - oldCost
			if delta >= 0 {
				travelIncrease := delta / (baseTravel + 1e-9)
				loadFactor := 1.0
				if ori.Load > 0 || des.Load > 0 {
					loadFactor = 1.0 + 0.5*float64(ori.Load+des.Load)/100.0
				}
				timePenalty := 0.0
				if ori.TimeStart > 0 && ori.TimeEnd > ori.TimeStart {
					windowSize := float64(ori.TimeEnd - ori.TimeStart)
					if windowSize < 120 {
						timePenalty = 20.0 / (windowSize + 10.0)
					}
				}
				score := delta*loadFactor*(1.0+timePenalty) + travelIncrease*50.0
				candidates = append(candidates, candidate{idx: ii, score: score, isNew: false, deltaCost: delta, travelOnly: travelIncrease})
			}
		}
	}

	if dispatch.AssignsLen < MAXASSIGNS {
		emptyIdx := dispatch.AssignsLen
		assignCopy := dispatch.Assigns[emptyIdx]
		ok := assignCopy.AddShip(shipID, ori, des)
		if ok {
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			if newCost >= 0 {
				score := newCost*1.3 + baseTravel*80.0
				candidates = append(candidates, candidate{idx: emptyIdx, score: score, isNew: true, deltaCost: newCost, travelOnly: baseTravel / (baseTravel + 1e-9)})
			}
		}
	}

	inserted := false

	if len(candidates) > 0 {
		bestScore := candidates[0].score
		bestIdx := candidates[0].idx
		bestIsNew := candidates[0].isNew
		for i := 1; i < len(candidates); i++ {
			if candidates[i].score < bestScore {
				bestScore = candidates[i].score
				bestIdx = candidates[i].idx
				bestIsNew = candidates[i].isNew
			} else if candidates[i].score == bestScore && !candidates[i].isNew && bestIsNew {
				bestIdx = candidates[i].idx
				bestIsNew = false
			}
		}
		ok := dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
		if ok {
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			inserted = true
		}
	}

	if !inserted {
		for ii := 0; ii <= dispatch.AssignsLen && ii < MAXASSIGNS; ii++ {
